import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation, Link } from 'react-router-dom';
import axios from 'axios';
import './Auth.css';   // Recommended to use this CSS file

const Auth = () => {
    const navigate = useNavigate();
    const location = useLocation();
    const isSignIn = location.pathname === '/signin';

    // Backgrounds
    const signInBg = "https://images.unsplash.com/photo-1518709268805-4e9042af2176?auto=format&fit=crop&w=1920&q=80";
    const signUpBg = "https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?auto=format&fit=crop&w=1920&q=80";
    const bg_image = isSignIn ? signInBg : signUpBg;

    // States
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [success, setSuccess] = useState("");

    // Sign In States
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [showPassword, setShowPassword] = useState(false);

    // Sign Up States
    const [formData, setFormData] = useState({
        username: "",
        email: "",
        password: "",
        confirmPassword: "",
        phone: "",
        agreeTerms: false
    });

    const [strength, setStrength] = useState({ score: 0, label: "", color: "transparent" });

    // Reset form when switching between Sign In and Sign Up
    useEffect(() => {
        resetForm();
    }, [isSignIn]);

    const resetForm = () => {
        setError("");
        setSuccess("");
        setEmail("");
        setPassword("");
        setFormData({
            username: "", email: "", password: "", confirmPassword: "", phone: "", agreeTerms: false
        });
        setStrength({ score: 0, label: "", color: "transparent" });
    };

    const evaluatePassword = (pass) => {
        if (!pass) return { score: 0, label: "", color: "transparent" };

        let score = 0;
        if (pass.length >= 8) score++;
        if (/[a-zA-Z]/.test(pass)) score++;
        if (/[0-9]/.test(pass)) score++;
        if (/[^A-Za-z0-9]/.test(pass)) score++;

        const levels = [
            { score: 25, label: "Weak", color: "#ff4d4d" },
            { score: 50, label: "Fair", color: "#ffa500" },
            { score: 75, label: "Good", color: "#2ecc71" },
            { score: 100, label: "Strong", color: "#1db954" }
        ];
        return levels[score - 1] || levels[0];
    };

    const handleChange = (e) => {
        const { name, value, type, checked } = e.target;
        const val = type === 'checkbox' ? checked : value;

        if (!isSignIn) {
            setFormData(prev => ({ ...prev, [name]: val }));
            if (name === "password") {
                setStrength(evaluatePassword(val));
            }
        }
    };

    // ==================== SIGN IN ====================
    const handleSignIn = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError("");
        setSuccess("");

        try {
            const formDataApi = new FormData();
            formDataApi.append('email', email);
            formDataApi.append('password', password);

            const response = await axios.post("https://lexluther.alwaysdata.net/api/signin", formDataApi);

            if (response.data.user || response.data.success) {
                setSuccess("Sign in successful! Redirecting...");
                localStorage.setItem("user", JSON.stringify(response.data.user || response.data));
                setTimeout(() => navigate("/"), 1500);
            } else {
                setError(response.data.message || "Invalid credentials");
            }
        } catch (err) {
            setError(err?.response?.data?.message || "Sign in failed. Please check your details.");
        } finally {
            setLoading(false);
        }
    };

    // ==================== SIGN UP ====================
    const handleSignUp = async (e) => {
        e.preventDefault();
        setError("");

        if (formData.password !== formData.confirmPassword) {
            setError("Passwords do not match.");
            return;
        }
        if (formData.password.length < 8) {
            setError("Password must be at least 8 characters long.");
            return;
        }
        if (!formData.agreeTerms) {
            setError("You must agree to the Terms & Conditions.");
            return;
        }

        setLoading(true);
        try {
            const data = new FormData();
            data.append('username', formData.username);
            data.append('email', formData.email);
            data.append('password', formData.password);
            if (formData.phone) data.append('phone', formData.phone);

            await axios.post("https://lexluther.alwaysdata.net/api/signup", data);

            setSuccess("Account created successfully! Redirecting to Sign In...");
            setTimeout(() => navigate("/signin"), 1800);
        } catch (err) {
            if (err?.response?.status === 409) {
                setError("Username or email already taken.");
            } else {
                setError(err?.response?.data?.message || "Signup failed.");
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="hero-container" style={{ backgroundImage: `url(${bg_image})` }}>
            <div className="vignette"></div>

            <div className="glass-card auth-card signup-card">
                <div className="auth-header">
                    <div className="nav-logo">PATHFINDER</div>
                    <h1>{isSignIn ? "Welcome Back" : "Join the Journey"}</h1>
                    <p>{isSignIn ? "Continue your journey" : "Create your account and start exploring"}</p>
                </div>

                <form onSubmit={isSignIn ? handleSignIn : handleSignUp}>
                    {error && <p className="error-message">{error}</p>}
                    {success && <p className="success-message">{success}</p>}

                    <div className="form-fields">
                        {!isSignIn && (
                            <div className="input-group">
                                <label>USERNAME</label>
                                <input
                                    type="text"
                                    name="username"
                                    placeholder="Choose a username"
                                    value={formData.username}
                                    onChange={handleChange}
                                    required
                                />
                            </div>
                        )}

                        <div className="input-group">
                            <label>EMAIL ADDRESS</label>
                            <input
                                type="email"
                                placeholder="Enter your email"
                                value={isSignIn ? email : formData.email}
                                onChange={isSignIn ? (e) => setEmail(e.target.value) : handleChange}
                                required
                            />
                        </div>

                        {!isSignIn && (
                            <div className="input-group">
                                <label>PHONE NUMBER (OPTIONAL)</label>
                                <input
                                    type="tel"
                                    name="phone"
                                    placeholder="Phone number"
                                    value={formData.phone}
                                    onChange={handleChange}
                                />
                            </div>
                        )}

                        <div className="input-group">
                            <label>PASSWORD</label>
                            <div className="password-wrapper">
                                <input
                                    type={showPassword ? "text" : "password"}
                                    placeholder={isSignIn ? "Enter password" : "Create password"}
                                    value={isSignIn ? password : formData.password}
                                    onChange={isSignIn ? (e) => setPassword(e.target.value) : handleChange}
                                    required
                                />
                                <button
                                    type="button"
                                    className="toggle-password"
                                    onClick={() => setShowPassword(!showPassword)}
                                >
                                    {showPassword ? "Hide" : "Show"}
                                </button>
                            </div>
                        </div>

                        {!isSignIn && formData.password && (
                            <div className="strength-container">
                                <div className="strength-bar">
                                    <div
                                        className="strength-progress"
                                        style={{ width: `${strength.score}%`, backgroundColor: strength.color }}
                                    />
                                </div>
                                <span className="strength-label" style={{ color: strength.color }}>
                                    {strength.label}
                                </span>
                            </div>
                        )}

                        {!isSignIn && (
                            <div className="input-group">
                                <label>CONFIRM PASSWORD</label>
                                <input
                                    type="password"
                                    name="confirmPassword"
                                    placeholder="Confirm password"
                                    value={formData.confirmPassword}
                                    onChange={handleChange}
                                    required
                                />
                            </div>
                        )}
                    </div>

                    {!isSignIn && (
                        <div className="terms-group">
                            <input
                                type="checkbox"
                                id="agreeTerms"
                                name="agreeTerms"
                                checked={formData.agreeTerms}
                                onChange={handleChange}
                            />
                            <label htmlFor="agreeTerms">
                                I agree to the <Link to="/terms" className="gold-link">Terms & Conditions</Link>
                            </label>
                        </div>
                    )}

                    <button type="submit" className="confirm-btn" disabled={loading}>
                        {loading 
                            ? (isSignIn ? "Signing In..." : "Creating Account...") 
                            : (isSignIn ? "SIGN IN" : "CREATE ACCOUNT")
                        }
                    </button>

                    <div className="auth-footer">
                        <p>
                            {isSignIn ? "Don't have an account?" : "Already have an account?"}{' '}
                            <Link 
                                to="#" 
                                onClick={(e) => { e.preventDefault(); navigate(isSignIn ? '/signup' : '/signin'); }}
                                className="gold-link"
                            >
                                {isSignIn ? "Create one" : "Sign In"}
                            </Link>
                        </p>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default Auth;
